import{_ as t,c as o,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Core Workflows: Systematic Development Process | Superpowers Tutorial","description":"Master the five core workflows of Superpowers: design, planning, TDD, debugging, and verification. Build systematic development habits.","frontmatter":{"title":"Core Workflows: Systematic Development Process | Superpowers Tutorial","sidebarTitle":"Core Workflows","subtitle":"Core Workflows: Systematic Development Process","description":"Master the five core workflows of Superpowers: design, planning, TDD, debugging, and verification. Build systematic development habits.","tags":["Core Workflows","Development Process","Systematic"],"order":100},"headers":[],"relativePath":"obra/superpowers/core-workflows/index.md","filePath":"obra/superpowers/core-workflows/index.md"}'),a={name:"obra/superpowers/core-workflows/index.md"};function s(n,e,l,d,c,h){return i(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="core-workflows-systematic-development-process" tabindex="-1">Core Workflows: Systematic Development Process <a class="header-anchor" href="#core-workflows-systematic-development-process" aria-label="Permalink to &quot;Core Workflows: Systematic Development Process&quot;">​</a></h1><p>This chapter introduces the five core workflows of Superpowers, helping you build systematic development habits. These workflows enforce best practices to ensure code quality, maintainability, and team collaboration efficiency.</p><div class="info custom-block"><p class="custom-block-title">Why do we need core workflows?</p><p>While AI agents are powerful, without constraints they tend to &quot;cut corners&quot; or over-rationalize. Core workflows provide clear boundaries and processes for AI agents, ensuring every step has verification and evidence.</p></div><h2 id="what-this-chapter-covers" tabindex="-1">What This Chapter Covers <a class="header-anchor" href="#what-this-chapter-covers" aria-label="Permalink to &quot;What This Chapter Covers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Course</th><th>Description</th><th>Difficulty</th></tr></thead><tbody><tr><td><a href="./../design-workflow/">Design Workflow: Brainstorming</a></td><td>Clarify requirements and design before coding to avoid wrong directions</td><td>⭐⭐</td></tr><tr><td><a href="./../planning-workflow/">Planning Workflow: Writing Plans</a></td><td>Write detailed implementation plans that engineers without context can execute</td><td>⭐⭐⭐</td></tr><tr><td><a href="./../tdd-workflow/">Test-Driven Development: TDD Iron Law</a></td><td>Deep dive into the RED-GREEN-REFACTOR cycle</td><td>⭐⭐⭐⭐</td></tr><tr><td><a href="./../debugging-workflow/">Debugging Workflow: Systematic Debugging</a></td><td>Four-phase systematic debugging process to avoid blind fixes</td><td>⭐⭐⭐</td></tr><tr><td><a href="./../verification-workflow/">Verification Workflow: Evidence First</a></td><td>Emphasize the &quot;evidence first&quot; principle to ensure genuine verification before claiming completion</td><td>⭐⭐</td></tr></tbody></table><h2 id="recommended-learning-path" tabindex="-1">Recommended Learning Path <a class="header-anchor" href="#recommended-learning-path" aria-label="Permalink to &quot;Recommended Learning Path&quot;">​</a></h2><h3 id="recommended-order-beginners" tabindex="-1">Recommended Order (Beginners) <a class="header-anchor" href="#recommended-order-beginners" aria-label="Permalink to &quot;Recommended Order (Beginners)&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Design Workflow&lt;br/&gt;Brainstorming] --&gt; B[Planning Workflow&lt;br/&gt;Writing Plans]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[TDD Workflow&lt;br/&gt;Test-Driven Development]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Debugging Workflow&lt;br/&gt;Systematic Debugging]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[Verification Workflow&lt;br/&gt;Verification Before Completion]</span></span></code></pre></div><ol><li><strong>Start with Design Workflow</strong>: Understand how to clarify requirements before coding</li><li><strong>Learn Planning Workflow</strong>: Master the skills of writing executable plans</li><li><strong>Deep Dive into TDD</strong>: This is the most core development process, focus on learning it</li><li><strong>Learn Debugging Workflow</strong>: Learn to systematically locate and fix issues</li><li><strong>Finally Learn Verification Workflow</strong>: Establish &quot;evidence first&quot; completion standards</li></ol><h3 id="advanced-learning-path" tabindex="-1">Advanced Learning Path <a class="header-anchor" href="#advanced-learning-path" aria-label="Permalink to &quot;Advanced Learning Path&quot;">​</a></h3><p>If you already have some experience, you can learn as needed:</p><ul><li><strong>Quick Start</strong>: Design Workflow + TDD Workflow</li><li><strong>Quality Improvement</strong>: TDD Workflow + Debugging Workflow + Verification Workflow</li><li><strong>Team Collaboration</strong>: Planning Workflow + Verification Workflow</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Please confirm before starting</p><ul><li>Completed <a href="./../../start/quick-start/">Quick Start</a></li><li>Mastered <a href="./../../start/using-skills/">How to Use Skills</a></li><li>Understand Superpowers core concepts (skills, sub-agents, hook system)</li></ul></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you can continue:</p><ul><li><a href="./../../advanced/">Advanced Workflows</a> - Learn advanced techniques like sub-agent driven development, code reviews, etc.</li><li><a href="./../../extending/">Extending Features</a> - Write custom skills to contribute to the team</li><li><a href="./../../faq/">FAQ</a> - View best practices and troubleshooting</li></ul><h2 id="value-of-this-chapter" tabindex="-1">Value of This Chapter <a class="header-anchor" href="#value-of-this-chapter" aria-label="Permalink to &quot;Value of This Chapter&quot;">​</a></h2><p>By learning core workflows, you will gain:</p><ul><li><strong>Systematic Thinking</strong>: No longer &quot;doing whatever comes to mind,&quot; but advancing development with a structured approach</li><li><strong>Quality Assurance</strong>: TDD iron law and verification workflows ensure code quality</li><li><strong>Efficiency Improvement</strong>: Design-first and planning workflows avoid wrong directions and rework</li><li><strong>Traceability</strong>: Each step has clear evidence and documentation</li></ul><div class="tip custom-block"><p class="custom-block-title">Remember</p><p>The essence of workflows is not to add process burden, but to reduce uncertainty and rework costs.</p></div>`,21)])])}const u=t(a,[["render",s]]);export{g as __pageData,u as default};
